function mouthSize(animal) {
    const lowerCaseAnimal = animal.toLowerCase();
    return lowerCaseAnimal === 'alligator' ? 'small' : 'wide';
}

console.log(mouthSize('alligator'));
console.log(mouthSize('ne alligator'));

function rank(score) {
    return score >= 100 ? 'Well done! You have advanced to the qualifying stage. Win 2 out of your next 3 games to rank up.' : false;
}

console.log(rank(120));
console.log(rank(99));

function close_compare(a, b, margin) {
    if (margin === undefined) margin = 0;
    if (a >= b) {
        if (a - b <= margin) {
            return 0;
        } else return 1;
    } else {
        if (b - a <= margin) {
            return 0;
        } else return -1;
    }
}

console.log(close_compare(1, 1, 1));
console.log(close_compare(5, 1, 1));
console.log(close_compare(1, 3, 1));
console.log(close_compare(1, 3, 2));
console.log(close_compare(1, 3));

function alcash(price, discount, total) {
    let amountWiskie = total / (price * (discount / 100));
    return Math.floor(amountWiskie);
}

console.log(alcash(10, 10, 500));
console.log(alcash(12, 50, 1000));

