const find = (array, element) => {
    const index = array.indexOf(element);
    return index !== -1 ? index : 'Not found';
}

console.log(find([1, 2, 3, 4, 5], 2));

function letters(prompt1, prompt2) {
    const isLetter = (str) => typeof str === 'string' && /^[a-zA-Zа-яА-ЯёЁ]$/.test(str);
    if (!isLetter(prompt1) || !isLetter(prompt2)) {
        return -1;
    }
    if (prompt1 === prompt1.toUpperCase() && prompt2 === prompt2.toUpperCase()) {
        return 1;
    } else {
        return 0;
    }
}

console.log(letters('a', 'b'));
console.log(letters('A', 0));
console.log(letters('A', 'B'));

const numbersArray = [-1, 2, -3, 4, 5];

function invertArray(numbersArray) {
    return numbersArray.map((num) => num === 0 ? 0 : -num);
}

console.log(invertArray([-1, 2, -3, 4, 5, 0]));
console.log(invertArray([]));

function anyArrows(arrows) {
    return arrows.some(arrow => arrow.damaged !== true);
}

console.log(anyArrows([{range: 5}, {range: 10, damaged: true}, {damaged: true}]));

